module BinaryCounter (
	input clk,
	input rst_n,
	input enable,
	output reg [3:0] counter_out
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            counter_out <= 4'b0000;
        end else if (enable) begin
            counter_out <= counter_out + 1;
        end
    end
endmodule
